import 'react-native-get-random-values';
import 'react-native-gesture-handler';
import React, { useEffect, useState } from 'react';
import { View, ActivityIndicator, Text, Platform, StyleSheet } from 'react-native';
import { GestureHandlerRootView } from 'react-native-gesture-handler';
import { NavigationContainer } from '@react-navigation/native';
import { createStackNavigator, CardStyleInterpolators } from '@react-navigation/stack';
import * as Updates from 'expo-updates';
import { StatusBar } from 'expo-status-bar';
import { initDB } from './src/database/database';
import AutoSyncService from './src/services/AutoSyncService';
import { AuthService } from './src/services/authService';
import LoginScreen from './src/screens/LoginScreen';
import HomeScreen from './src/screens/HomeScreen';
import ColheitaScreen from './src/screens/ColheitaScreen';
import VendasScreen from './src/screens/VendasScreen';
import EstoqueScreen from './src/screens/EstoqueScreen';
import SyncScreen from './src/screens/SyncScreen';
import ComprasScreen from './src/screens/ComprasScreen';
import PlantioScreen from './src/screens/PlantioScreen';
import CustosScreen from './src/screens/CustosScreen';
import ProcessamentoScreen from './src/screens/ProcessamentoScreen';
import RelatoriosScreen from './src/screens/RelatoriosScreen';
import RegisterScreen from './src/screens/RegisterScreen';
import MonitoramentoScreen from './src/screens/MonitoramentoScreen';
import CadastroScreen from './src/screens/CadastroScreen';
import ClientesScreen from './src/screens/ClientesScreen';
import CulturasScreen from './src/screens/CulturasScreen';
import UsuariosScreen from './src/screens/UsuariosScreen';
import OcrScreen from './src/screens/OcrScreen';
import ScannerScreen from './src/screens/ScannerScreen';
import CadernoCampoScreen from './src/screens/CadernoCampoScreen';
import FrotaScreen from './src/screens/FrotaScreen';
import MaquinaFormScreen from './src/screens/MaquinaFormScreen';
import ProfileScreen from './src/screens/ProfileScreen';
import ProfileEditScreen from './src/screens/ProfileEditScreen';
import SettingsScreen from './src/screens/SettingsScreen';
import AdubacaoListScreen from './src/screens/AdubacaoListScreen';
import AdubacaoFormScreen from './src/screens/AdubacaoFormScreen';
import AdubacaoDetailScreen from './src/screens/AdubacaoDetailScreen';
import ClienteFormScreen from './src/screens/ClienteFormScreen';
import CadastroFormScreen from './src/screens/CadastroFormScreen';
import MenuCadastrosScreen from './src/screens/MenuCadastrosScreen';
import ForgotPasswordScreen from './src/screens/ForgotPasswordScreen';
import RecoverScreen from './src/screens/RecoverScreen';
import ResetPasswordScreen from './src/screens/ResetPasswordScreen';
import VerifyCodeScreen from './src/screens/VerifyCodeScreen';
import EncomendasScreen from './src/screens/EncomendasScreen';
import NovaEncomendaScreen from './src/screens/NovaEncomendaScreen';
import GraficosScreen from './src/screens/GraficosScreen';
import IntelligenceScreen from './src/screens/IntelligenceScreen';
import CategoriasDespesaScreen from './src/screens/CategoriasDespesaScreen';
import FinancialAccountsScreen from './src/screens/FinancialAccountsScreen';
import { supabase } from './src/services/supabaseClient';

import ErrorBoundary from './src/ui/ErrorBoundary';
import { WeatherProvider } from './src/context/WeatherContext';
import { ThemeProvider } from './src/theme/ThemeContext';
import Toast from './src/ui/Toast';

const Stack = createStackNavigator();

export default function App() {
    const [isDbReady, setIsDbReady] = useState(false);
    const [userSession, setUserSession] = useState(null);
    const [isLoading, setIsLoading] = useState(true);
    const [initError, setInitError] = useState(null);

    useEffect(() => {
        async function checkUpdates() {
            try {
                if (!__DEV__) {
                    const update = await Updates.checkForUpdateAsync();
                    if (update.isAvailable) {
                        console.log("Baixando atualiza├º├úo OTA...");
                        await Updates.fetchUpdateAsync();
                        // Comentado para evitar loops infinitos em builds locais/pessoais (v1.1.6)
                        // await Updates.reloadAsync(); 
                    }
                }
            } catch (err) {
                console.log("Erro ao checar OTA Updates:", err);
            }
        }
        // checkUpdates(); // Desativado at├® confirma├º├úo de estabilidade no APK local

        initDB()
            .then(async () => {
                const session = await AuthService.checkSession();
                setUserSession(session);
                setIsDbReady(true);
                setIsLoading(false);
            })
            .catch(error => {
                const erroStr = error?.message || String(error);
                if (__DEV__) console.error("Falha fatal na inicializa├º├úo do App:", erroStr);
                setInitError(erroStr);
                setIsDbReady(true);
                setIsLoading(false);
            });

        const { data: authListener } = supabase.auth.onAuthStateChange(async (event, session) => {
            if (__DEV__) console.log(`[App] Evento Auth: ${event}`);
            if (event === 'SIGNED_IN' || event === 'TOKEN_REFRESHED') {
                const mappedSession = session ? {
                    userId: session.user.id,
                    email: session.user.email,
                    token: session.access_token
                } : null;
                setUserSession(mappedSession);
            } else if (event === 'SIGNED_OUT') {
                setUserSession(null);
            }
        });

        return () => {
            AutoSyncService.stop();
            authListener?.subscription.unsubscribe();
        };
    }, []);

    if (isLoading || !isDbReady) {
        return (
            <View style={{ flex: 1, backgroundColor: '#0B121E', justifyContent: 'center', alignItems: 'center' }}>
                <ActivityIndicator size="large" color="#10B981" />
                <Text style={{ color: '#64748B', marginTop: 10 }}>Carregando sistema...</Text>
            </View>
        );
    }

    if (initError) {
        return (
            <View style={{ flex: 1, backgroundColor: '#0B121E', justifyContent: 'center', alignItems: 'center', padding: 20 }}>
                <Text style={{ color: '#EF4444', fontSize: 18, fontWeight: 'bold', marginBottom: 10 }}>Erro Cr├¡tico</Text>
                <Text style={{ color: '#fff', textAlign: 'center' }}>N├úo foi poss├¡vel iniciar o aplicativo:</Text>
                <Text style={{ color: '#F87171', textAlign: 'center', marginTop: 10 }}>{initError}</Text>
            </View>
        );
    }

    return (
        <View style={styles.webRoot}>
            <View style={styles.appContainer}>
                <GestureHandlerRootView style={{ flex: 1 }}>
            <ErrorBoundary>
                <ThemeProvider>
                    <WeatherProvider>
                        <StatusBar style="light" />
                        <NavigationContainer>
                            <Stack.Navigator
                                screenOptions={{
                                    headerShown: false,
                                    headerStyle: { backgroundColor: '#10B981' },
                                    headerTintColor: '#fff',
                                    headerTitleStyle: { fontWeight: 'bold' },
                                    cardStyleInterpolator: CardStyleInterpolators.forHorizontalIOS,
                                    transitionSpec: {
                                        open: { animation: 'timing', config: { duration: 250 } },
                                        close: { animation: 'timing', config: { duration: 250 } }
                                    }
                                }}
                            >
                                {!userSession ? (
                                    // STACK DE AUTENTICA├ç├âO (Sempre blindada contra loops)
                                    <>
                                        <Stack.Screen name="Login" options={{ headerShown: false }}>
                                            {(props) => <LoginScreen {...props} onLoginSuccess={(sess) => setUserSession(sess)} />}
                                        </Stack.Screen>
                                        <Stack.Screen name="Register" component={RegisterScreen} options={{ headerShown: false }} />
                                        <Stack.Screen name="ForgotPassword" component={ForgotPasswordScreen} options={{ title: 'Recuperar Senha' }} />
                                        <Stack.Screen name="Recover" component={RecoverScreen} options={{ title: 'Recupera├º├úo' }} />
                                        <Stack.Screen name="VerifyCode" component={VerifyCodeScreen} options={{ title: 'Verificar C├│digo' }} />
                                        <Stack.Screen name="ResetPassword" component={ResetPasswordScreen} options={{ title: 'Nova Senha' }} />
                                    </>
                                ) : (
                                    // STACK DO APLICATIVO (S├│ renderiza se estiver logado)
                                    <>
                                        <Stack.Screen name="Dashboard" component={HomeScreen} options={{ headerShown: false }} />
                                        <Stack.Screen name="Colheita" component={ColheitaScreen} options={{ title: 'Registrar Colheita' }} />
                                        <Stack.Screen name="Vendas" component={VendasScreen} options={{ title: 'Registrar Venda' }} />
                                        <Stack.Screen name="Estoque" component={EstoqueScreen} options={{ title: 'Consultar Estoque' }} />
                                        <Stack.Screen name="Sync" component={SyncScreen} />
                                        {/* Profile foi movido para baixo com options */}
                                        <Stack.Screen name="ProfileEdit" component={ProfileEditScreen} />
                                        <Stack.Screen name="Settings" component={SettingsScreen} />
                                        {/* MenuCadastros foi movido para baixo com options */}
                                        <Stack.Screen name="Compras" component={ComprasScreen} options={{ title: 'Registrar Compra' }} />
                                        <Stack.Screen name="Plantio" component={PlantioScreen} options={{ title: 'Registrar Plantio' }} />
                                        <Stack.Screen name="Custos" component={CustosScreen} options={{ title: 'Registrar Custo' }} />
                                        <Stack.Screen name="Processamento" component={ProcessamentoScreen} options={{ title: 'Processamento & Perdas' }} />
                                        <Stack.Screen name="Cadastro" component={CadastroScreen} options={{ title: 'Cadastros Gerais' }} />
                                        <Stack.Screen name="Clientes" component={ClientesScreen} options={{ title: 'Gerenciar Clientes' }} />
                                        <Stack.Screen name="Culturas" component={CulturasScreen} options={{ title: 'Culturas e ├üreas' }} />
                                        <Stack.Screen name="Relatorios" component={RelatoriosScreen} options={{ title: 'Relat├│rios' }} />
                                        <Stack.Screen name="Usuarios" component={UsuariosScreen} options={{ title: 'Controle de Usu├írios' }} />
                                        <Stack.Screen name="Monitoramento" component={MonitoramentoScreen} options={{ title: 'Monitoramento' }} />
                                        <Stack.Screen name="Ocr" component={OcrScreen} options={{ headerShown: false }} />
                                        <Stack.Screen name="Scanner" component={ScannerScreen} options={{ headerShown: false }} />
                                        <Stack.Screen name="CadernoCampo" component={CadernoCampoScreen} options={{ title: 'Caderno de Campo' }} />
                                        <Stack.Screen name="Frota" component={FrotaScreen} options={{ title: 'Gest├úo de Frota' }} />
                                        <Stack.Screen name="MaquinaForm" component={MaquinaFormScreen} options={{ title: 'Cadastro de M├íquina' }} />
                                        <Stack.Screen name="Profile" component={ProfileScreen} options={{ title: 'Meu Perfil' }} />
                                        <Stack.Screen name="AdubacaoList" component={AdubacaoListScreen} options={{ title: 'Planos de Aduba├º├úo' }} />
                                        <Stack.Screen name="AdubacaoForm" component={AdubacaoFormScreen} options={{ title: 'Novo Plano' }} />
                                        <Stack.Screen name="AdubacaoDetail" component={AdubacaoDetailScreen} options={{ title: 'Detalhes do Plano' }} />
                                        <Stack.Screen name="ClienteForm" component={ClienteFormScreen} options={{ title: 'Novo Cliente' }} />
                                        <Stack.Screen name="CadastroForm" component={CadastroFormScreen} options={{ title: 'Novo Cadastro' }} />
                                        <Stack.Screen name="MenuCadastros" component={MenuCadastrosScreen} options={{ title: 'Menu de Cadastros' }} />
                                        <Stack.Screen name="Encomendas" component={EncomendasScreen} options={{ title: 'Minhas Encomendas' }} />
                                        <Stack.Screen name="NovaEncomenda" component={NovaEncomendaScreen} options={{ title: 'Nova Encomenda' }} />
                                        <Stack.Screen name="Graficos" component={GraficosScreen} options={{ title: 'Resumo de Gr├íficos' }} />
                                        <Stack.Screen name="Intelligence" component={IntelligenceScreen} options={{ headerShown: false }} />
                                        <Stack.Screen name="CategoriasDespesa" component={CategoriasDespesaScreen} options={{ title: 'Categorias de Despesa' }} />
                                        <Stack.Screen name="FinancialAccounts" component={FinancialAccountsScreen} options={{ title: 'Contas Financeiras' }} />
                                    </>
                                )}
                            </Stack.Navigator>
                        </NavigationContainer>
                        <Toast />
                    </WeatherProvider>
                </ThemeProvider>
            </ErrorBoundary>
                </GestureHandlerRootView>
            </View>
        </View>
    );
}

const styles = StyleSheet.create({
    webRoot: {
        flex: 1,
        backgroundColor: '#050a0a',
        alignItems: Platform.OS === 'web' ? 'center' : 'stretch',
    },
    appContainer: {
        flex: 1,
        width: '100%',
        maxWidth: Platform.OS === 'web' ? 480 : '100%',
        backgroundColor: '#f8fafc',
        overflow: 'hidden',
    }
});

import { SyncWorker } from '../src/services/SyncWorker';
import NetInfo from '@react-native-community/netinfo';
import { executeQuery } from '../src/database/database';

// Mocks
jest.mock('@react-native-community/netinfo', () => ({
  fetch: jest.fn(),
}));

jest.mock('../src/database/database', () => ({
  executeQuery: jest.fn(),
}));

jest.mock('../src/services/supabaseClient', () => ({
  supabase: {
    from: jest.fn(() => ({
      upsert: jest.fn(() => ({ error: null })),
      delete: jest.fn(() => ({ eq: jest.fn(() => ({ error: null })) })),
    })),
  },
}));

describe('SyncWorker Audit', () => {
  beforeEach(() => {
    jest.clearAllMocks();
  });

  it('deve interromper o ciclo se n├úo houver internet', async () => {
    NetInfo.fetch.mockResolvedValue({ isConnected: false });

    await SyncWorker.run();

    expect(executeQuery).not.toHaveBeenCalled();
  });

  it('deve processar itens da fila quando houver internet', async () => {
    NetInfo.fetch.mockResolvedValue({ isConnected: true });
    executeQuery.mockResolvedValue({
      rows: {
        length: 1,
        item: (_) => ({
          id: '1',
          table_name: 'test_table',
          operation: 'INSERT',
          record_id: 'rec_1',
          payload: JSON.stringify({ name: 'Test' }),
        }),
      },
    });

    await SyncWorker.run();

    expect(executeQuery).toHaveBeenCalled();
    // Verifica se tentou atualizar o status para processing
    expect(executeQuery).toHaveBeenCalledWith(
      expect.stringContaining('UPDATE v2_sync_queue SET status = \'processing\''),
      expect.anything()
    );
  });
});

// src/components/monitoramento/RegistroItem.js
import React from 'react';
import { View, Text, StyleSheet, TouchableOpacity } from 'react-native';
import { useTheme } from '../../theme/ThemeContext';
import { Ionicons } from '@expo/vector-icons';
import GlowCard from '../../ui/GlowCard';

/**
 * Props:
 *   item: {
 *     id: string,
 *     tipo: 'praga' | 'doenca' | 'observacao',
 *     intensidade?: 'baixa' | 'media' | 'alta',
 *     descricao: string,
 *     fotos?: string[], // array of image URIs (optional)
 *     pdfUrl?: string   // optional PDF URL
 *   }
 */
export default function RegistroItem({ item }) {
  const { colors, isDark } = useTheme();

  const getTipoLabel = () => {
    switch (item.tipo) {
      case 'praga': return 'PRAGA';
      case 'doenca': return 'DOEN├çA';
      default: return 'OBSERVA├ç├âO';
    }
  };

  const getCorIntensidade = () => {
    switch (item.intensidade) {
      case 'alta': return colors.danger || '#E74C3C'; 
      case 'media': return colors.warning || '#F39C12';
      case 'baixa': return colors.info || '#3B82F6';
      default: return colors.border || '#BDC3C7';
    }
  };

  return (
    <GlowCard style={styles.card}>
      {/* Header with type and optional intensity tag */}
      <View style={styles.topo}>
        <View style={{flexDirection: 'row', alignItems: 'center'}}>
           <Ionicons name="finger-print-outline" size={16} color={colors.textSecondary} style={{marginRight: 6}} />
           <Text style={[styles.tipo, { color: colors.textPrimary }]}>{getTipoLabel()}</Text>
        </View>

        {item.intensidade && (
          <View style={[styles.tag, { backgroundColor: getCorIntensidade() + '20', borderColor: getCorIntensidade() + '50', borderWidth: 1 }]}>
            <Text style={[styles.tagText, { color: getCorIntensidade() }]}>{item.intensidade.toUpperCase()}</Text>
          </View>
        )}
      </View>

      {/* Description */}
      <Text style={[styles.descricao, { color: colors.textSecondary }]}>{item.descricao}</Text>

      {/* Footer with photo count and optional PDF button */}
      <View style={[styles.footer, { borderTopColor: colors.border }]}>
        <Text style={[styles.fotos, { color: colors.textMuted }]}>
           <Ionicons name="camera-outline" size={14} /> {item.fotos?.length || 0} foto(s)
        </Text>
        {item.pdfUrl && (
          <TouchableOpacity style={[styles.pdfBtn, { borderColor: colors.primary, backgroundColor: colors.primary + '10' }]} onPress={() => {
            console.log('Abrir PDF:', item.pdfUrl);
          }}>
            <Ionicons name="document-text" size={12} color={colors.primary} />
            <Text style={[styles.pdfText, { color: colors.primary }]}> PDF</Text>
          </TouchableOpacity>
        )}
      </View>
    </GlowCard>
  );
}

const styles = StyleSheet.create({
  card: {
    padding: 16,
    marginBottom: 12,
  },
  topo: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
    marginBottom: 10,
  },
  tipo: {
    fontSize: 13,
    fontWeight: '800',
    letterSpacing: 0.5
  },
  tag: {
    paddingHorizontal: 8,
    paddingVertical: 4,
    borderRadius: 8,
  },
  tagText: {
    fontSize: 9,
    fontWeight: '900',
  },
  descricao: {
    fontSize: 13,
    marginBottom: 16,
    lineHeight: 18
  },
  footer: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
    borderTopWidth: 1,
    paddingTop: 12
  },
  fotos: {
    fontSize: 12,
    fontWeight: '700'
  },
  pdfBtn: {
    flexDirection: 'row',
    alignItems: 'center',
    paddingHorizontal: 12,
    paddingVertical: 6,
    borderRadius: 8,
    borderWidth: 1,
  },
