import * as SQLite from 'expo-sqlite';
import { v4 } from 'uuid';
import { Platform } from 'react-native';

import { SCHEMA_V10 } from './schema_v10';

import { V1_DIAMOND_PRO } from './migrations/v1_diamond_pro';

const __DEV__ = typeof __DEV__ !== 'undefined' ? __DEV__ : true;
let db;

// Fun├º├úo auxiliar para promissificar o executeSql
export const executeQuery = (sql, params = []) => {
    return new Promise((resolve, reject) => {
        if (!db) {
            reject(new Error('Banco n├úo inicializado'));
            return;
        }
        
        // Timeout de seguran├ºa de 30s por query (v10.7 Gold)
        const queryTimeout = setTimeout(() => {
            console.warn('­ƒòÆ [SQL TIMEOUT CR├ìTICO]:', sql.substring(0, 100));
            reject(new Error('Timeout de execu├º├úo SQL'));
        }, 30000);

        try {
            db.transaction(tx => {
                const start = Date.now();
                tx.executeSql(
                    sql,
                    params,
                    (_, result) => {
                        clearTimeout(queryTimeout);
                        const duration = Date.now() - start;
                        if (__DEV__ && duration > 1000) {
                            console.log(`ÔÜá´©Å Query Lenta (${duration}ms):`, sql.substring(0, 100));
                        }
                        resolve(result);
                    },
                    (_, error) => {
                        clearTimeout(queryTimeout);
                        if (__DEV__) console.log('ÔÜá´©Å Erro SQL:', sql, error.message);
                        reject(error);
                    }
                );
            }, (txError) => {
                clearTimeout(queryTimeout);
                reject(txError);
            });
        } catch (e) {
            clearTimeout(queryTimeout);
            reject(e);
        }
    });
};

/**
 * Executa m├║ltiplas queries em uma ├ÜNICA transa├º├úo at├┤mica
 * Essencial para evitar bloqueios de banco na inicializa├º├úo
 */
export const executeTransaction = (queries) => {
    return new Promise((resolve, reject) => {
        if (!db) return reject(new Error('Banco n├úo inicializado'));
        
        db.transaction(tx => {
            queries.forEach(sql => {
                tx.executeSql(sql, [], null, (_, err) => {
                    console.warn('ÔÜá´©Å Erro em lote:', sql.substring(0, 50), err.message);
                    return false; // continua execu├º├úo
                });
            });
        }, 
        (err) => reject(err), 
        () => resolve());
    });
};

export const initDB = async () => {
    try {
        if (Platform.OS === 'web') {
            console.log('­ƒîÉ Web mode detected. Using Mock DB to prevent crashes.');
            db = {
                transaction: (txFn, errFn, successFn) => {
                    try {
                        txFn({
                            executeSql: (sql, params, succ, err) => {
                                if (succ) succ(null, { rows: { length: 0, item: () => null, _array: [] } });
                            }
                        });
                        if (successFn) successFn();
                    } catch (e) {
                        if (errFn) errFn(e);
                    }
                }
            };
            return db;
        }

        db = SQLite.openDatabase('agrogb_mobile.db');
        
        if (__DEV__) console.log('Ô£à Banco de dados aberto modo padr├úo (SDK 50)');
        await createTables();
        return db;
    } catch (error) {
        console.error('[DATABASE ERROR] Erro ao abrir banco:', error);
        throw error;
    }
};

const createTables = async () => {
    try {
        if (__DEV__) console.log(`­ƒÆÄ v1.1 DIAMOND: Iniciando transa├º├úo AT├öMICA TOTAL para ${V1_DIAMOND_PRO.length} comandos...`);
        const start = Date.now();
        
        // Inclui SCHEMA_V10 se dispon├¡vel
        const allQueries = [...V1_DIAMOND_PRO, ...SCHEMA_V10];
        await executeTransaction(allQueries);
        if (__DEV__) console.log(`Ô£¿ DIAMOND SETUP em ${Date.now() - start}ms`);

        // --- TAREFAS PESADAS (RODAM APENAS UMA VEZ) ---
        const lastCleanup = await getConfig('LAST_HEAVY_CLEANUP');
        const today = new Date().toISOString().split('T')[0];

        if (lastCleanup !== today) {
            if (__DEV__) console.log('­ƒÜÇ Executando manuten├º├Áes pesadas di├írias...');
            await deduplicateClientes();
            
            const countKnowledge = await executeQuery('SELECT COUNT(*) as c FROM base_conhecimento_pro');
            if (countKnowledge.rows.item(0).c === 0) {
                await seedKnowledgeBasePro();
            }
            await setConfig('LAST_HEAVY_CLEANUP', today);
        }

        if (__DEV__) console.log("Ô£à Ciclo de inicializa├º├úo DIAMOND finalizado.");

    } catch (error) {
        console.error('ÔØî ERRO CR├ìTICO DIAMOND SETUP:', error);
    }
};

export const deduplicateClientes = async () => {
    try {
        if (__DEV__) console.log('­ƒº╣ Iniciando deduplica├º├úo OTIMIZADA de clientes (SQL Express)...');
        
        // Estrat├®gia SQL: Marca como deletado todos os registros que tenham Nome/CPF duplicado, 
        // mantendo apenas o ID mais antigo. Muito mais r├ípido que loop JS.
        await executeQuery(`
            UPDATE clientes 
            SET is_deleted = 1, sync_status = 0 
            WHERE id NOT IN (
                SELECT MIN(id) 
                FROM clientes 
                WHERE is_deleted = 0 
                GROUP BY UPPER(TRIM(nome)), COALESCE(TRIM(cpf_cnpj), '')
            ) AND is_deleted = 0
        `);

        if (__DEV__) console.log('Ô£à Deduplica├º├úo conclu├¡da via SQL Unit├írio.');
    } catch (e) {
        console.error('ÔØî Erro na deduplica├º├úo de clientes:', e);
    }
};

// --- SEED PRO ---
const seedKnowledgeBasePro = async () => {
    try {
        const seeds = [
            // SOJA
