                            </TouchableOpacity>

                            {/* NOME */}
                            <Text style={styles.fieldLabel}>NOME DO ITEM *</Text>
                            <TextInput
                                style={styles.input}
                                value={nome}
                                onChangeText={t => up(t, setNome)}
                                placeholder="Ex: Adubo 20-00-20, Bocashi..."
