                            />

                            {/* UNIDADE */}
                            <Text style={styles.fieldLabel}>UNIDADE DE MEDIDA</Text>
                            <View style={styles.unidadeGrid}>
                                {UNIDADES.map(u => (
                                    <TouchableOpacity
                                        key={u}
