import { getCulturas } from '../database/database';

const screenWidth = Dimensions.get('window').width;

export default function CulturasScreen({ navigation }) {
    const [items, setItems] = useState([]);
    const [filter, setFilter] = useState('Todas');
    const [searchQuery, setSearchQuery] = useState('');
    
    // Form Modal State
    const [modalVisible, setModalVisible] = useState(false);
    const [formData, setFormData] = useState({ nome: '', variedade: '', area: '', status: 'Plantado' });

    useEffect(() => { loadData(); }, []);

    const loadData = async () => {
        try { 
            const data = await getCulturas(); 
            setItems(data.length > 0 ? data : [
                { id: '1', nome: 'Morango', variedade: 'Albion', area: '1.2 ha', plantio: '10/01/2026', status: 'Produ├º├úo', total: '3,200 kg' },
                { id: '2', nome: 'Milho', variedade: 'H├¡brido', area: '8.5 ha', plantio: '05/03/2026', status: 'Desenvolvimento', total: '5,000 kg' },
                { id: '3', nome: 'Caf├®', variedade: 'Ar├íbica', area: '5.0 ha', plantio: '12/08/2025', status: 'Plantado', total: '1,800 kg' },
                { id: '4', nome: 'Alface', variedade: 'Crespa', area: '1.5 ha', plantio: '20/09/2024', status: 'Finalizado', total: '900 kg' },
            ]); 
        } catch {}
    };

    const handleSave = async () => {
        if (!formData.nome || !formData.area) {
            Alert.alert('Erro', 'Preencha os campos obrigat├│rios (Nome e ├ürea).');
