                                <View style={styles.inputWrapper}>
                                    <Ionicons name="flask-outline" size={18} color="#3B82F6" style={styles.inputIcon} />
                                    <TextInput 
                                        style={styles.modalInput} 
                                        placeholder="Ex: H├¡brido XP, Palmer..." 
                                        placeholderTextColor="#64748B"
