                                </LinearGradient>
                                <Text style={styles.emptyTitle}>Armaz├®m vazio</Text>
                                <Text style={styles.emptyDesc}>
                                    {searchText ? 'Nenhum item encontrado para esta busca.' : 'Cadastre insumos para o controle di├írio.'}
