/**
 * LoginScreen.js ÔÇö AgroGB OS
 * R├®plica exata da imagem "perfeita" enviada pelo usu├írio:
 * - Fundo azul marinho escuro sem foto
 * - Inputs flutuantes sem card de fundo
 * - Bot├úo com degrad├¬ verde para azul (ENTRAR NO SISTEMA)
 * - Biometria centralizada abaixo do bot├úo
 * - Rodap├® "CRIAR NOVA CONTA  ÔÇó  RECUPERAR SENHA"
 */

import React, { useState, useEffect, useRef } from 'react';
import {
    View, Text, StyleSheet, Image, KeyboardAvoidingView,
    Platform, Alert, StatusBar, TouchableOpacity,
    TextInput, ActivityIndicator, ScrollView,
    Dimensions, Animated
} from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { LinearGradient } from 'expo-linear-gradient';
import { Ionicons, MaterialCommunityIcons } from '@expo/vector-icons';
import { AuthService } from '../services/authService';
import * as LocalAuthentication from 'expo-local-authentication';

const { width, height } = Dimensions.get('window');

export default function LoginScreen({ navigation, onLoginSuccess }) {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [loading, setLoading] = useState(false);
    const [isBiometricAvailable, setIsBiometricAvailable] = useState(false);
    const [secureText, setSecureText] = useState(true);

    const fadeAnim = useRef(new Animated.Value(0)).current;
    const slideAnim = useRef(new Animated.Value(30)).current;

    useEffect(() => {
        Animated.parallel([
            Animated.timing(fadeAnim, { toValue: 1, duration: 800, useNativeDriver: true }),
            Animated.timing(slideAnim, { toValue: 0, duration: 800, useNativeDriver: true }),
        ]).start();
    }, []);

    useEffect(() => {
        const checkBiometry = async () => {
            try {
                const hasHardware = await LocalAuthentication.hasHardwareAsync();
                const isEnrolled = await LocalAuthentication.isEnrolledAsync();
                setIsBiometricAvailable(hasHardware && isEnrolled);
            } catch { setIsBiometricAvailable(false); }
        };
        checkBiometry();
    }, []);

    const handleLogin = async () => {
        if (!email || !password) return Alert.alert('Acesso Restrito', 'Preencha todos os campos.');
        realLoginFlow(email, password);
    };

    const handleBiometricLogin = async () => {
        setLoading(true);
        try {
            const res = await AuthService.loginWithBiometrics();
            if (res.success) { if (onLoginSuccess) onLoginSuccess(res.user); }
            else Alert.alert('Biometria', res.message || 'Falha na autentica├º├úo.');
        } catch { Alert.alert('Erro', 'Falha ao processar biometria.'); }
        finally { setLoading(false); }
    };

    const realLoginFlow = async (em, pwd) => {
        setLoading(true);
        const watchdog = setTimeout(() => {
            setLoading(false);
            Alert.alert('Servidor Lento', 'O sistema est├í demorando mais que o normal.');
        }, 60000);
        try {
            const res = await AuthService.login(em, pwd);
            clearTimeout(watchdog);
            if (res.success) {
                const alreadyAsked = await AsyncStorage.getItem('@asked_biometrics');
                const hardware = await LocalAuthentication.hasHardwareAsync();
                const enrolled = await LocalAuthentication.isEnrolledAsync();
                if (hardware && !alreadyAsked && enrolled) {
                    Alert.alert('Acesso Biom├®trico', 'Ativar acesso por digital?', [
                        { text: 'Agora n├úo', onPress: async () => { await AsyncStorage.setItem('@asked_biometrics', 'false'); if (onLoginSuccess) onLoginSuccess(res.user); } },
                        { text: 'Sim', onPress: async () => { await AsyncStorage.setItem('@asked_biometrics', 'true'); if (onLoginSuccess) onLoginSuccess(res.user); } }
                    ]);
                } else { if (onLoginSuccess) onLoginSuccess(res.user); }
            } else Alert.alert('Acesso Negado', res.message || 'Credenciais inv├ílidas.');
        } catch {
            clearTimeout(watchdog);
            Alert.alert('Erro', 'N├úo foi poss├¡vel completar o acesso.');
        } finally {
            clearTimeout(watchdog);
            setLoading(false);
        }
    };

    return (
        <KeyboardAvoidingView behavior={Platform.OS === 'ios' ? 'padding' : 'height'} style={styles.root}>
            <StatusBar barStyle="light-content" translucent backgroundColor="transparent" />

            {/* ÔöÇÔöÇ BACKGROUND ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */}
            <View style={StyleSheet.absoluteFill}>
                {/* Degrad├¬ Azul Escuro (Navy) */}
                <LinearGradient
                    colors={['#05111C', '#0B1626', '#0A1523', '#060D15']}
                    style={StyleSheet.absoluteFill}
                />
                {/* Formas sutis (c├¡rculos) no fundo para dar a textura da imagem */}
                <View style={[styles.bgCircle, { top: -100, right: -150, width: 400, height: 400, backgroundColor: 'rgba(16, 50, 70, 0.2)' }]} />
                <View style={[styles.bgCircle, { bottom: -50, left: -100, width: 300, height: 300, backgroundColor: 'rgba(16, 40, 70, 0.3)' }]} />
            </View>

            <ScrollView contentContainerStyle={styles.scroll} showsVerticalScrollIndicator={false} keyboardShouldPersistTaps="handled">

                <Animated.View style={[{ opacity: fadeAnim, transform: [{ translateY: slideAnim }], flex: 1, justifyContent: 'space-between' }]}>

                    <View>
                        {/* ÔöÇÔöÇ LOGO E T├ìTUTLOS ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */}
                        <View style={styles.logoBlock}>
                            <Image
                                source={require('../../assets/logo_agrogb.jpg')}
                                style={styles.logoImage}
                                resizeMode="contain"
                            />
                            <Text style={styles.brandTitle}>AgroGB</Text>
                            <Text style={styles.brandSubtitle}>SISTEMA DE GEST├âO PROFISSIONAL</Text>
                        </View>

                        {/* ÔöÇÔöÇ INPUTS (sem card, flutuantes) ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */}
                        <View style={styles.formSection}>

                            {/* E-mail ou Usu├írio */}
                            <Text style={styles.fieldLabel}>E-MAIL OU USU├üRIO</Text>
                            <View style={styles.inputRow}>
                                <Ionicons name="person-outline" size={20} color="#6B7280" />
                                <TextInput
                                    style={styles.input}
                                    placeholder="ex: admin@agrogb.com"
                                    placeholderTextColor="#4B5563"
                                    value={email}
                                    onChangeText={setEmail}
                                    autoCapitalize="none"
                                    keyboardType="email-address"
                                />
                            </View>

                            {/* Senha */}
                            <Text style={[styles.fieldLabel, { marginTop: 24 }]}>SENHA DE ACESSO</Text>
                            <View style={styles.inputRow}>
                                <Ionicons name="lock-closed-outline" size={20} color="#6B7280" />
                                <TextInput
                                    style={styles.input}
                                    placeholder="ÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇó"
                                    placeholderTextColor="#4B5563"
                                    value={password}
                                    onChangeText={setPassword}
                                    secureTextEntry={secureText}
                                />
                                <TouchableOpacity onPress={() => setSecureText(!secureText)}>
                                    <Ionicons
                                        name={secureText ? 'eye-off-outline' : 'eye-outline'}
                                        size={22}
                                        color="#6B7280"
                                    />
                                </TouchableOpacity>
                            </View>

                            {/* Bot├úo ENTRAR (Verde para Azul) */}
                            <TouchableOpacity style={styles.enterBtn} onPress={handleLogin} disabled={loading} activeOpacity={0.87}>
                                <LinearGradient
                                    colors={['#178243', '#25508D']} // Degrad├¬ Verde->Azul exato do print
                                    start={{ x: 0, y: 0 }} end={{ x: 1, y: 0 }}
                                    style={styles.enterBtnGradient}
                                >
                                    {loading ? <ActivityIndicator color="#FFF" size="small" /> : <Text style={styles.enterBtnText}>ENTRAR NO SISTEMA</Text>}
                                </LinearGradient>
                            </TouchableOpacity>
                        </View>
                    </View>

                    {/* ÔöÇÔöÇ BIOMETRIA E RODAP├ë ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */}
                    <View style={styles.bottomSection}>
                        <View style={styles.bioContainer}>
                            <Text style={styles.bioTitle}>OU ACESSE COM DIGITAL</Text>
                            <TouchableOpacity onPress={handleBiometricLogin} style={styles.fpButtonContainer} activeOpacity={0.8}>
                                <View style={styles.fpGlow}>
                                    <MaterialCommunityIcons name="fingerprint" size={38} color="#10B981" />
                                </View>
                            </TouchableOpacity>
                        </View>

                        {/* Footer Links */}
                        <View style={styles.footerRow}>
                            <TouchableOpacity onPress={() => navigation?.navigate?.('Register')}>
                                <Text style={styles.footerLink}>CRIAR NOVA CONTA</Text>
                            </TouchableOpacity>

                            <Text style={styles.footerDot}>ÔÇó</Text>

                            <TouchableOpacity onPress={() => navigation?.navigate?.('ForgotPassword')}>
                                <Text style={styles.footerLink}>RECUPERAR SENHA</Text>
                            </TouchableOpacity>
                        </View>
                    </View>
                </Animated.View>
            </ScrollView>
