                    {/* ÔöÇÔöÇ FORM CARD ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */}
                    <View style={styles.formSection}>

                        {step === 1 ? (
