                    {/* QUANTIDADE E PRE├çO */}
                    <View style={styles.formGrid}>
                        <View style={{ flex: 1 }}>
                            <Text style={styles.sectionTitle}>QUANTIDADE</Text>
                            <SafeBlurView intensity={20} style={styles.inputPill} webFallbackColor="rgba(255,255,255,0.02)">
                                <TextInput
